    .search([
      {
        indexName: this.config.algolia.indexName,
        params: {
          query: query,
          maxValuesPerFacet: MAX_VALUE_PER_FACET,
          attributesToRetrieve: [
            'hierarchy.lvl0',
            'hierarchy.lvl1',
            'hierarchy.lvl2',
            'hierarchy.lvl3',
            'hierarchy.lvl4',
            'hierarchy.lvl5',
            'hierarchy.lvl6',
            'content',
            'type',
            'url',
          ],
          hitsPerPage: 20,
          snippetEllipsisText: '…',
          highlightPreTag: '<ɵ>',
          highlightPostTag: '</ɵ>',
          attributesToHighlight: [],
          attributesToSnippet: [
            'hierarchy.lvl1:10',
