(): ApiItemsGroup[] => {
  const query = this.form.query().value().toLocaleLowerCase();
  const status = this.form.status().value();
  const type = this.form.type().value();
  return this.apiReferenceManager
    .apiGroups()
    .map((group) => ({
      title: group.title,
      id: group.id,
      items: group.items.filter((apiItem) => {
        return (
          (query == ''
            ? true
            : apiItem.title.toLocaleLowerCase().includes(query) ||
              group.title.toLocaleLowerCase().includes(query)) &&
          (type === ALL_TYPES_KEY || apiItem.itemType === type) &&
          ((status & STATUSES.stable &&
            !apiItem.developerPreview &&
            !apiItem.deprecated &&
            !apiItem.experimental) ||
            (status & STATUSES.deprecated && apiItem.deprecated) ||
            (status & STATUSES.developerPreview && apiItem.developerPreview) ||
            (status & STATUSES.experimental && apiItem.experimental))
        );
      }),
    }))
    .filter(
      (group) =>
        group.items.length > 0 &&
        (this.form.selectedPackage().value() === ALL_PACKAGES ||
          group.id === this.form.selectedPackage().value()),
    );
}

() => {
  const month = this.viewMonth();

  const daysInMonth = this._dateAdapter.getNumDaysInMonth(month);
  const dateNames = this._dateAdapter.getDateNames();

  const calendar: CalendarCell[][] = [[]];
  for (let i = 0, cell = this._firstWeekOffset(); i < daysInMonth; i++, cell++) {
    if (cell == DAYS_PER_WEEK) {
      calendar.push([]);
      cell = 0;
    }
    const date = this._dateAdapter.createDate(
      this._dateAdapter.getYear(month),
      this._dateAdapter.getMonth(month),
      i + 1,
    );
    const ariaLabel = this._dateAdapter.format(date, this._dateFormats.display.dateA11yLabel);

    calendar[calendar.length - 1].push({
      displayName: dateNames[i],
      ariaLabel,
      date,
      selected: signal(
        this._dateAdapter.compareDate(
          date,
          untracked(() => this.selectedDate()),
        ) === 0,
      ),
      day: i + 1,
    });
  }

  return calendar;
}

gameLoop() {
  const keys = this.pressedKeys();
  if (!this.isDialogOpen()) {
    const currentPos = this.characterPosition();
    let newPos = {...currentPos};
    let moveDirection: 'horizontal' | 'vertical' | null = null;

    if (keys.has('ArrowUp')) {
      newPos.y -= MOVE_STEP;
      moveDirection = 'vertical';
      this.walkingDirection.set('up');
    } else if (keys.has('ArrowDown')) {
      newPos.y += MOVE_STEP;
      moveDirection = 'vertical';
      this.walkingDirection.set('down');
    } else if (keys.has('ArrowLeft')) {
      newPos.x -= MOVE_STEP;
      moveDirection = 'horizontal';
      this.walkingDirection.set('left');
    } else if (keys.has('ArrowRight')) {
      newPos.x += MOVE_STEP;
      moveDirection = 'horizontal';
      this.walkingDirection.set('right');
    } else {
      this.walkingDirection.set(null);
    }

    if (moveDirection && this.isMoveAllowed(currentPos, newPos, moveDirection)) {
      this.characterPosition.set(newPos);
      this.walkFrame.update((frame) => frame + 1);
    }
  }

  requestAnimationFrame(() => this.gameLoop());
}

(prop: unknown): PropType => {
  if (isSignal(prop)) {
    const {error, value} = safelyReadSignalValue(prop);
    if (error) {
      return PropType.Unknown;
    }
    prop = value;
  }

  if (prop === undefined) {
    return PropType.Undefined;
  }
  if (prop === null) {
    return PropType.Null;
  }
  if (prop instanceof HTMLElement) {
    return PropType.HTMLNode;
  }
  const type = typeof prop;
  if (type in commonTypes) {
    return commonTypes[type as keyof typeof commonTypes];
  }
  if (type === 'object') {
    if (Array.isArray(prop)) {
      return PropType.Array;
    } else if (prop instanceof Set) {
      return PropType.Set;
    } else if (prop instanceof Map) {
      return PropType.Map;
    } else if (Object.prototype.toString.call(prop) === '[object Date]') {
      return PropType.Date;
    } else if (prop instanceof Node) {
      return PropType.HTMLNode;
    } else {
      return PropType.Object;
    }
  }
  return PropType.Unknown;
}

(data: FlatNode[]): NestedProp[] => {
  const getChildren = (prop: Descriptor) => {
    if ((prop.type === PropType.Object || prop.type === PropType.Array) && prop.value) {
      return Object.entries(prop.value).map(
        ([k, v]: [string, any]): {name: number | string; children: NestedProp[]} => {
          return {
            name: prop.type === PropType.Array ? parseInt(k, 10) : k,
            children: getChildren(v),
          };
        },
      );
    }
    return [];
  };

  const getExpandedProperties = (props: {[name: string]: Descriptor}) => {
    return Object.keys(props).map((name) => {
      return {
        name,
        children: getChildren(props[name]),
      };
    });
  };

  const parents: {[name: string]: Descriptor} = {};

  for (const node of data) {
    let prop = node.prop;
    while (prop.parent) {
      prop = prop.parent;
    }
    parents[prop.name] = prop.descriptor;
  }

  return getExpandedProperties(parents);
}

buildKeyframes(): AnimationTimelineInstruction {
  this.applyStylesToKeyframe();
  const preStyleProps = new Set<string>();
  const postStyleProps = new Set<string>();
  const isEmpty = this._keyframes.size === 1 && this.duration === 0;

  let finalKeyframes: Array<ɵStyleDataMap> = [];
  this._keyframes.forEach((keyframe, time) => {
    const finalKeyframe = new Map([...this._backFill, ...keyframe]);
    finalKeyframe.forEach((value, prop) => {
      if (value === PRE_STYLE) {
        preStyleProps.add(prop);
      } else if (value === AUTO_STYLE) {
        postStyleProps.add(prop);
      }
    });
    if (!isEmpty) {
      finalKeyframe.set('offset', time / this.duration);
    }
    finalKeyframes.push(finalKeyframe);
  });

  const preProps: string[] = [...preStyleProps.values()];
  const postProps: string[] = [...postStyleProps.values()];

  // special case for a 0-second animation (which is designed just to place styles onscreen)
  if (isEmpty) {
    const kf0 = finalKeyframes[0];
    const kf1 = new Map(kf0);
    kf0.set('offset', 0);
    kf1.set('offset', 1);
    finalKeyframes = [kf0, kf1];
  }

  return createTimelineInstruction(
    this.element,
    finalKeyframes,
    preProps,
    postProps,
    this.duration,
    this.startTime,
    this.easing,
    false,
  );
}

function buildRootMap(roots: any[], nodes: any[]): Map<any, any[]> {
  const rootMap = new Map<any, any[]>();
  roots.forEach((root) => rootMap.set(root, []));

  if (nodes.length == 0) return rootMap;

  const NULL_NODE = 1;
  const nodeSet = new Set(nodes);
  const localRootMap = new Map<any, any>();

  function getRoot(node: any): any {
    if (!node) return NULL_NODE;

    let root = localRootMap.get(node);
    if (root) return root;

    const parent = node.parentNode;
    if (rootMap.has(parent)) {
      // ngIf inside @trigger
      root = parent;
    } else if (nodeSet.has(parent)) {
      // ngIf inside ngIf
      root = NULL_NODE;
    } else {
      // recurse upwards
      root = getRoot(parent);
    }

    localRootMap.set(node, root);
    return root;
  }

  nodes.forEach((node) => {
    const root = getRoot(node);
    if (root !== NULL_NODE) {
      rootMap.get(root)!.push(node);
    }
  });

  return rootMap;
}

export function getDayPeriods(
  localeData: CldrLocaleData,
  dayPeriodsList: string[],
): {
  format: {
    narrow: Record<string, string>;
    abbreviated: Record<string, string>;
    wide: Record<string, string>;
  };
  'stand-alone': {
    narrow: Record<string, string>;
    abbreviated: Record<string, string>;
    wide: Record<string, string>;
  };
} {
  const dayPeriods = localeData.main(`dates/calendars/gregorian/dayPeriods`);
  const result: any = {};
  // cleaning up unused keys
  Object.keys(dayPeriods).forEach((key1) => {
    // format / stand-alone
    result[key1] = {};
    Object.keys(dayPeriods[key1]).forEach((key2) => {
      // narrow / abbreviated / wide
      result[key1][key2] = {};
      Object.keys(dayPeriods[key1][key2]).forEach((key3) => {
        if (dayPeriodsList.indexOf(key3) !== -1) {
          result[key1][key2][key3] = dayPeriods[key1][key2][key3];
        }
      });
    });
  });

  return result as any;
}

ngOnChanges(changes: SimpleChanges<NgOptimizedImage>) {
  if (ngDevMode) {
    assertNoPostInitInputChange(this, changes, [
      'ngSrcset',
      'width',
      'height',
      'priority',
      'fill',
      'loading',
      'sizes',
      'loaderParams',
      'disableOptimizedSrcset',
    ]);
  }
  if (changes['ngSrc'] && !changes['ngSrc'].isFirstChange()) {
    const oldSrc = this._renderedSrc;
    this.updateSrcAndSrcset(true);

    if (ngDevMode) {
      const newSrc = this._renderedSrc;
      if (oldSrc && newSrc && oldSrc !== newSrc) {
        const ngZone = this.injector.get(NgZone);
        ngZone.runOutsideAngular(() => {
          this.lcpObserver!.updateImage(oldSrc, newSrc);
        });
      }
    }
  }

  if (
    ngDevMode &&
    changes['placeholder']?.currentValue &&
    typeof ngServerMode !== 'undefined' &&
    !ngServerMode
  ) {
    assertPlaceholderDimensions(this, this.imgElement);
  }
}

function toHostMetadata<TExpression>(
  metaObj: AstObject<R3DeclareDirectiveMetadata, TExpression>,
): R3HostMetadata {
  if (!metaObj.has('host')) {
    return {
      attributes: {},
      listeners: {},
      properties: {},
      specialAttributes: {},
    };
  }

  const host = metaObj.getObject('host');

  const specialAttributes: R3HostMetadata['specialAttributes'] = {};
  if (host.has('styleAttribute')) {
    specialAttributes.styleAttr = host.getString('styleAttribute');
  }
  if (host.has('classAttribute')) {
    specialAttributes.classAttr = host.getString('classAttribute');
  }

  return {
    attributes: host.has('attributes')
      ? host.getObject('attributes').toLiteral((value) => value.getOpaque())
      : {},
    listeners: host.has('listeners')
      ? host.getObject('listeners').toLiteral((value) => value.getString())
      : {},
    properties: host.has('properties')
      ? host.getObject('properties').toLiteral((value) => value.getString())
      : {},
    specialAttributes,
  };
}

export function isAngularCorePackage(program: ts.Program): boolean {
  // Look for its_just_angular.ts somewhere in the program.
  const r3Symbols = getR3SymbolsFile(program);
  if (r3Symbols === null) {
    return false;
  }

  // Look for the constant ITS_JUST_ANGULAR in that file.
  return r3Symbols.statements.some((stmt) => {
    // The statement must be a variable declaration statement.
    if (!ts.isVariableStatement(stmt)) {
      return false;
    }
    // It must be exported.
    const modifiers = ts.getModifiers(stmt);
    if (
      modifiers === undefined ||
      !modifiers.some((mod) => mod.kind === ts.SyntaxKind.ExportKeyword)
    ) {
      return false;
    }
    // It must declare ITS_JUST_ANGULAR.
    return stmt.declarationList.declarations.some((decl) => {
      // The declaration must match the name.
      if (!ts.isIdentifier(decl.name) || decl.name.text !== 'ITS_JUST_ANGULAR') {
        return false;
      }
      // It must initialize the variable to true.
      if (decl.initializer === undefined || decl.initializer.kind !== ts.SyntaxKind.TrueKeyword) {
        return false;
      }
      // This definition matches.
      return true;
    });
  });
}

private renderTableOfContents(element: HTMLElement): void {
  if (!this.hasToc()) {
    return;
  }

  let firstHeading = element.querySelector<HTMLElement>('h2,h3[id]');
  if (!firstHeading) {
    return;
  }

  // If the first header is in a card container element, place TOC element
  // before the container.
  const parentEl = firstHeading.parentElement;
  if (parentEl && parentEl.classList.contains('docs-card-container-header')) {
    firstHeading = parentEl.parentElement;
  }

  // Since the content of the main area is dynamically created and there is
  // no host element for a ToC component, we create it manually.
  let tocHostElement: HTMLElement | null = element.querySelector(TOC_HOST_ELEMENT_NAME);
  if (!tocHostElement) {
    tocHostElement = this.document.createElement(TOC_HOST_ELEMENT_NAME);
    tocHostElement.setAttribute(TOC_SKIP_CONTENT_MARKER, 'true');
    firstHeading?.parentNode?.insertBefore(tocHostElement, firstHeading);
  }

  this.renderComponent(TableOfContents, tocHostElement, {contentSourceElement: element});
}

private setupPageNavigationDimming() {
  if (this.isServer) {
    return;
  }
  this.router.events
    .pipe(
      filter((e) => e instanceof NavigationStart),
      map(() => {
        // Only apply set the property if the navigation is not "immediate"
        return setTimeout(() => {
          this.progressBar().start();
        }, PROGRESS_BAR_DELAY);
      }),
      switchMap((timeoutId) => {
        return this.router.events.pipe(
          filter((e) => {
            return (
              e instanceof NavigationEnd ||
              e instanceof NavigationCancel ||
              e instanceof NavigationSkipped ||
              e instanceof NavigationError
            );
          }),
          take(1),
          map(() => timeoutId),
        );
      }),
    )
    .subscribe((timeoutId) => {
      // When the navigation finishes, prevent the navigating class from being applied in the timeout.
      clearTimeout(timeoutId);
      this.progressBar().complete();
    });
}

function getAutocompleteProposals(
  request: ActionMessage<AutocompleteRequest>,
): ActionMessage<AutocompleteResponse> {
  if (!env) {
    return {
      action: TsVfsWorkerActions.AUTOCOMPLETE_RESPONSE,
      data: [],
    };
  }

  updateFile(env, request.data!.file, request.data!.content);

  const completions = languageService!.getCompletionsAtPosition(
    request.data!.file,
    request.data!.position,
    USER_PREFERENCES,
    FORMAT_CODE_SETTINGS,
  );

  const completionsWithImportSuggestions = completions?.entries.map((entry) => {
    if (entry.source) {
      const entryDetails = languageService!.getCompletionEntryDetails(
        request.data!.file,
        request.data!.position,
        entry.name,
        FORMAT_CODE_SETTINGS,
        entry.source,
        USER_PREFERENCES,
        entry.data,
      );

      if (entryDetails?.codeActions) {
        return {
          ...entry,
          codeActions: entryDetails?.codeActions,
        };
      }
    }

    return entry;
  });

  return {
    action: TsVfsWorkerActions.AUTOCOMPLETE_RESPONSE,
    data: completionsWithImportSuggestions,
  };
}

private validateRules(rule: AnimationRule<Styles>) {
  if (!rule.timeframe) {
    return;
  }

  const duration = rule.timeframe[1] - rule.timeframe[0];
  if (duration < 0) {
    throw new Error(
      `Animation: Incorrect time frame for selector '${rule.selector}'. Start time is greater than end time`,
    );
  } else if (duration === 0) {
    throw new Error(
      `Animation: Duration for selector '${rule.selector}' is zero. Use 'at' time selector instead`,
    );
  }

  const fromStyles = Object.keys(rule.from);
  const toStyles = Object.keys(rule.to);

  if (fromStyles.length !== toStyles.length) {
    throw new Error(
      `Animation: There is a mismatch between the number of "from" and "to" styles for selector '${rule.selector}'`,
    );
  }
  for (const prop of toStyles) {
    if (!rule.from[prop]) {
      throw new Error(
        `Animation: "from" style '${prop}' is missing for selector '${rule.selector}'`,
      );
    }
  }
}

function calculateNextTransformValue(
  srcValue: TransformValue,
  targetValue: TransformValue,
  changeRate: number,
): TransformValue {
  const nextValue: TransformValue = {
    type: 'transform',
    values: new Map(),
  };

  for (const [func, numData] of targetValue.values) {
    const srcNumData = srcValue.values.get(func)!;
    const newNumData: [number, string][] = [];

    for (let i = 0; i < numData.length; i++) {
      const target = numData[i];
      const src = srcNumData[i];
      const numDelta = calculateValueDelta(src[0], target[0], changeRate);
      // We should check both source and target for the unit
      // since we might have zero-based value without a unit
      // (e.g. rotate(0) <-> rotate(180deg))
      const unit = target[1] || src[1];
      newNumData.push([src[0] + numDelta, unit]);
    }

    nextValue.values.set(func, newNumData);
  }

  return nextValue;
}

export function cssValueLexer(value: string): (string | number)[] {
  const tokens: (string | number)[] = [];
  let buffer = '';
  let bufferType: BufferType | null = null;

  const addToken = () => tokens.push(bufferType === 'number' ? parseFloat(buffer) : buffer);

  for (const char of value) {
    const charType = getCharType(char);
    const newBufferType = getBufferType(charType, bufferType);

    // Check if token end has been reached
    if (END_SYMBOLS.includes(charType) && buffer) {
      addToken();
      buffer = '';
      bufferType = null;
    } else if (newBufferType !== null) {
      if (newBufferType !== bufferType && bufferType !== null) {
        // Handle a new token/token change
        addToken();
        buffer = char;
        bufferType = newBufferType;
      } else if (newBufferType === bufferType || bufferType === null) {
        // Accumulate token string
        buffer += char;
        bufferType = newBufferType;
      }
    }
  }

  // If the buffer is still filled,
  // add the remaing as the last token
  if (buffer) {
    addToken();
  }

  return tokens;
}

(tokens) => {
  if (typeof tokens[0] === 'number') {
    const value: NumericValue = {
      type: 'numeric',
      values: [],
    };
    let buffer = [];

    for (const token of tokens) {
      if (typeof token === 'number') {
        // Add a value to the list (with or without unit)
        if (buffer.length) {
          value.values.push((buffer.length === 1 ? [buffer[0], ''] : buffer) as [number, string]);
          buffer = [];
        }

        buffer.push(token);
      } else if (buffer.length === 1) {
        // If string, expect a numeric value (i.e. buffer.length == 1) in the buffer.
        buffer.push(token);
      } else {
        // Any other case means, the value is invalid.
        return null;
      }
    }

    // Add any remaining values in the buffer
    if (buffer.length) {
      value.values.push((buffer.length === 1 ? [buffer[0], ''] : buffer) as [number, string]);
    }

    return value;
  }

  return null;
}

(messageBus: MessageBus<Events>) => () => {
  const ng = ngDebugClient();

  const forest = initializeOrGetDirectiveForestHooks().getIndexedDirectiveForest();
  if (forest.length === 0) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const rootNode = forest[0];
  if (!rootNode || !rootNode.nativeElement) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const injector = getInjectorFromElementNode(rootNode.nativeElement);
  if (!injector) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const transferStateData = (ng.ɵgetTransferState?.(injector) ?? null) as Record<
    string,
    TransferStateValue
  > | null;

  if (
    transferStateData &&
    typeof transferStateData === 'object' &&
    Object.keys(transferStateData).length > 0
  ) {
    messageBus.emit('transferStateData', [transferStateData]);
  } else {
    messageBus.emit('transferStateData', [null]);
  }
}

(messageBus: MessageBus<Events>) => (element: ElementPosition) => {
  const ng = ngDebugClient();

  // get injector from position
  const node = queryDirectiveForest(
    element,
    initializeOrGetDirectiveForestHooks().getIndexedDirectiveForest(),
  );
  if (!node) {
    messageBus.emit('latestSignalGraph', [null]);
    return;
  }

  const injector = node.injector ?? getInjectorFromElementNode(node.nativeElement!);

  if (!injector) {
    messageBus.emit('latestSignalGraph', [null]);
    return;
  }

  const graph = ng.ɵgetSignalGraph?.(injector);
  if (graph) {
    const nodes = graph.nodes.map<DebugSignalGraphNode>((node) => {
      return {
        id: node.id,
        kind: node.kind,
        label: node.label,
        epoch: node.epoch,
        preview: serializeValue(node.value),
        debuggable: !!node.debuggableFn,
      };
    });
    messageBus.emit('latestSignalGraph', [{nodes, edges: graph.edges}]);
  }
}

export function mapToDevtoolsControlFlowModel(
  block: ControlFlowBlockInternal,
  iteratorCurrentIdx: number,
  rootId: number,
): ControlFlowBlock {
  switch (block.type) {
    case ControlFlowBlockTypeInternal.For:
      const serializedItems = block.items.map((item) => serializeValue(item, 5));

      return {
        id: `forId-${rootId}-${iteratorCurrentIdx}`,
        type: ControlFlowBlockType.For,
        hasEmptyBlock: block.hasEmptyBlock,
        items: serializedItems,
        trackExpression: block.trackExpression,
      } satisfies ForLoopBlock as ForLoopBlock;

    case ControlFlowBlockTypeInternal.Defer:
      return {
        id: `deferId-${rootId}-${iteratorCurrentIdx}`,
        type: ControlFlowBlockType.Defer,
        state: block.state,
        renderedBlock: getRenderedBlock(block),
        triggers: groupTriggers(block.triggers),
        blocks: {
          hasErrorBlock: block.hasErrorBlock,
          placeholderBlock: block.placeholderBlock,
          loadingBlock: block.loadingBlock,
        },
      } satisfies DeferBlock as DeferBlock;
  }
}

private _getNode(lView: LView, data: any, idx: number): ComponentTreeNode {
  const directives: DirectiveInstanceType[] = [];
  let component: ComponentInstanceType | null = null;
  const tNode = data[idx];
  const node = lView[idx][ELEMENT];
  const element = (node.tagName || node.nodeName).toLowerCase();
  if (!tNode) {
    return {
      nativeElement: node,
      children: [],
      element,
      directives: [],
      component: null,
      controlFlowBlock: null, // neither there will be any control flow block
    };
  }
  for (let i = tNode.directiveStart; i < tNode.directiveEnd; i++) {
    const instance = lView[i];
    const dirMeta = data[i];
    if (dirMeta && dirMeta.template) {
      component = {
        name: element,
        isElement: isCustomElement(node),
        instance,
      };
    } else if (dirMeta) {
      directives.push({
        name: getDirectiveName(instance),
        instance,
      });
    }
  }
  return {
    nativeElement: node,
    children: [],
    element,
    directives,
    component,
    controlFlowBlock: null, // neither there will be any control flow block
  };
}

override connect(collectionViewer: CollectionViewer): Observable<FlatNode[]> {
  const changed = this._treeControl.expansionModel.changed;
  if (!changed) {
    throw new Error('Unable to subscribe to the expansion model change');
  }
  const s = changed.subscribe((change: SelectionChange<FlatNode>) => {
    if (change.added) {
      change.added.forEach((node) => this._toggleNode(node, true));
    }
    if (change.removed) {
      change.removed.reverse().forEach((node) => this._toggleNode(node, false));
    }
  });
  this._subscriptions.push(s);

  const changes = [
    collectionViewer.viewChange,
    this._treeControl.expansionModel.changed,
    this._data,
  ];

  return merge<unknown[]>(...changes).pipe(
    map(() => {
      this._expandedData.next(
        this._treeFlattener.expandFlattenedNodes(this.data, this._treeControl),
      );
      return this._expandedData.value;
    }),
  );
}

highlightDependencies(node: DevtoolsSignalGraphNode, direction: 'down' | 'up') {
  if (!this.inputGraph) {
    return;
  }

  const nodeIdx = this.inputGraph.nodes.findIndex((n) => node === n);
  if (nodeIdx === -1) {
    return;
  }

  this.unhighlightNodesAndEdges();

  const pathNodesIds = new Set<string>();
  const edges = new Set<string>();
  const stack = [nodeIdx];
  const nodes = this.inputGraph.nodes;

  while (stack.length) {
    const currentIdx = stack.pop()!;

    for (const edge of this.inputGraph.edges) {
      const currNodeIdx = direction === 'down' ? edge.producer : edge.consumer;

      if (currNodeIdx === currentIdx) {
        const nextNodeIdx = direction === 'down' ? edge.consumer : edge.producer;

        pathNodesIds.add(nodes[nextNodeIdx].id);
        edges.add(`${nodes[edge.producer].id}-${nodes[edge.consumer].id}`);
        stack.push(nextNodeIdx);
      }
    }
  }

  this.highlightEdges(edges);
  this.highlightNodesPath(node.id, pathNodesIds);

  for (const cb of this.dependenciesHighlightListeners) {
    cb({
      node,
      direction,
      state: 'highlighted',
    });
  }
}

invokeQuery(
  selector: string,
  originalSelector: string,
  limit: number,
  includeSelf: boolean,
  optional: boolean,
  errors: Error[],
): any[] {
  let results: any[] = [];
  if (includeSelf) {
    results.push(this.element);
  }
  if (selector.length > 0) {
    // only if :self is used then the selector can be empty
    selector = selector.replace(ENTER_TOKEN_REGEX, '.' + this._enterClassName);
    selector = selector.replace(LEAVE_TOKEN_REGEX, '.' + this._leaveClassName);
    const multi = limit != 1;
    let elements = this._driver.query(this.element, selector, multi);
    if (limit !== 0) {
      elements =
        limit < 0
          ? elements.slice(elements.length + limit, elements.length)
          : elements.slice(0, limit);
    }
    results.push(...elements);
  }

  if (!optional && results.length == 0) {
    errors.push(invalidQuery(originalSelector));
  }
  return results;
}

private applyUpdate(update: Update): void {
  const key = update.name.toLowerCase();
  switch (update.op) {
    case 'a':
    case 's':
      let value = update.value!;
      if (typeof value === 'string') {
        value = [value];
      }
      if (value.length === 0) {
        return;
      }
      this.maybeSetNormalizedName(update.name, key);
      const base = (update.op === 'a' ? this.headers.get(key) : undefined) || [];
      base.push(...value);
      this.headers.set(key, base);
      break;
    case 'd':
      const toDelete = update.value as string | undefined;
      if (!toDelete) {
        this.headers.delete(key);
        this.normalizedNames.delete(key);
      } else {
        let existing = this.headers.get(key);
        if (!existing) {
          return;
        }
        existing = existing.filter((value) => toDelete.indexOf(value) === -1);
        if (existing.length === 0) {
          this.headers.delete(key);
          this.normalizedNames.delete(key);
        } else {
          this.headers.set(key, existing);
        }
      }
      break;
  }
}

serializeBody(): ArrayBuffer | Blob | FormData | URLSearchParams | string | null {
  // If no body is present, no need to serialize it.
  if (this.body === null) {
    return null;
  }
  // Check whether the body is already in a serialized form. If so,
  // it can just be returned directly.
  if (
    typeof this.body === 'string' ||
    isArrayBuffer(this.body) ||
    isBlob(this.body) ||
    isFormData(this.body) ||
    isUrlSearchParams(this.body)
  ) {
    return this.body;
  }
  // Check whether the body is an instance of HttpUrlEncodedParams.
  if (this.body instanceof HttpParams) {
    return this.body.toString();
  }
  // Check whether the body is an object or array, and serialize with JSON if so.
  if (
    typeof this.body === 'object' ||
    typeof this.body === 'boolean' ||
    Array.isArray(this.body)
  ) {
    return JSON.stringify(this.body);
  }
  // Fall back on toString() for everything else.
  return (this.body as any).toString();
}

function createCloudinaryUrl(path: string, config: ImageLoaderConfig) {
  // Cloudinary image URLformat:
  // https://cloudinary.com/documentation/image_transformations#transformation_url_structure
  // Example of a Cloudinary image URL:
  // https://res.cloudinary.com/mysite/image/upload/c_scale,f_auto,q_auto,w_600/marketing/tile-topics-m.png

  // For a placeholder image, we use the lowest image setting available to reduce the load time
  // else we use the auto size
  const quality = config.isPlaceholder ? 'q_auto:low' : 'q_auto';

  let params = `f_auto,${quality}`;
  if (config.width) {
    params += `,w_${config.width}`;
  }

  if (config.height) {
    params += `,h_${config.height}`;
  }

  if (config.loaderParams?.['rounded']) {
    params += `,r_max`;
  }

  // Allows users to add any Cloudinary transformation parameters as a string or object
  if (config.loaderParams?.['transform']) {
    const transformStr = normalizeLoaderTransform(config.loaderParams['transform'], '_');
    params += `,${transformStr}`;
  }

  return `${path}/image/upload/${params}/${config.src}`;
}
